import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import doctorService from '../../services/doctorService';
import DoctorStatusBadge from '../../components/doctors/DoctorStatusBadge';

const DAYS = ['MON','TUE','WED','THU','FRI','SAT','SUN'];
const DAY_LABELS = { MON:'Monday',TUE:'Tuesday',WED:'Wednesday',THU:'Thursday',FRI:'Friday',SAT:'Saturday',SUN:'Sunday' };

function DoctorMyProfilePage() {
  const navigate = useNavigate();
  const [doctor, setDoctor]   = useState(null);
  const [loading, setLoading] = useState(true);
  const [slots, setSlots]     = useState([]);
  const [newSlot, setNewSlot] = useState({ day:'MON', start_time:'09:00', end_time:'10:00' });
  const [slotLoading, setSlotLoading] = useState(false);

  const fetch = async () => {
    try {
      const [profileData, slotData] = await Promise.all([
        doctorService.getMyProfile(),
        doctorService.getSlots(),
      ]);
      setDoctor(profileData.data);
      setSlots(slotData.data || []);
    } catch {
      setDoctor(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetch(); }, []);

  const handleAddSlot = async () => {
    setSlotLoading(true);
    try {
      await doctorService.addSlot(newSlot);
      toast.success('Slot added!');
      fetch();
    } catch (err) {
      const msg = err.response?.data?.non_field_errors?.[0] || 'Failed to add slot.';
      toast.error(msg);
    } finally {
      setSlotLoading(false); }
  };

  const handleDeleteSlot = async (id) => {
    try {
      await doctorService.deleteSlot(id);
      toast.success('Slot removed.');
      fetch();
    } catch { toast.error('Failed to delete slot.'); }
  };

  if (loading) return (
    <div className="flex items-center justify-center py-24">
      <svg className="animate-spin w-8 h-8 text-teal-500" fill="none" viewBox="0 0 24 24">
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
      </svg>
    </div>
  );

  if (!doctor) return (
    <div className="text-center py-20 max-w-md mx-auto">
      <div className="w-14 h-14 mx-auto mb-4 bg-teal-50 rounded-full flex items-center justify-center">
        <svg className="w-7 h-7 text-teal-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5}
            d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/>
        </svg>
      </div>
      <h3 className="text-sm font-semibold text-gray-900 mb-2">No Doctor Profile Found</h3>
      <p className="text-xs text-gray-500 mb-4">Register your professional profile to get started.</p>
      <button onClick={() => navigate('/doctors/register')}
        className="px-5 py-2 text-xs font-medium text-white bg-teal-600 rounded-lg hover:bg-teal-700">
        + Register Profile
      </button>
    </div>
  );

  return (
    <div className="max-w-2xl mx-auto space-y-4">
      <div className="flex items-center justify-between">
        <h1 className="text-lg font-bold text-gray-900">My Doctor Profile</h1>
        <DoctorStatusBadge status={doctor.status} />
      </div>

      {/* Status Banner */}
      {doctor.status === 'PENDING' && (
        <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4 flex items-center gap-3">
          <span className="text-lg">⏳</span>
          <p className="text-xs text-yellow-800">
            Your profile is <strong>pending approval</strong> from your hospital admin.
          </p>
        </div>
      )}
      {doctor.status === 'APPROVED' && (
        <div className="bg-green-50 border border-green-200 rounded-xl p-4 flex items-center gap-3">
          <span className="text-lg">✅</span>
          <p className="text-xs text-green-800">
            Your profile is <strong>approved</strong> and visible to patients!
          </p>
        </div>
      )}
      {doctor.status === 'REJECTED' && (
        <div className="bg-red-50 border border-red-200 rounded-xl p-4">
          <p className="text-xs font-semibold text-red-800 mb-1">Profile Rejected</p>
          <p className="text-xs text-red-700">{doctor.rejection_reason || 'Contact support.'}</p>
        </div>
      )}

      {/* Profile Card */}
      <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
        <div className="bg-gradient-to-r from-teal-700 to-teal-900 px-5 py-4 text-white">
          <h2 className="font-bold">Dr. {doctor.full_name}</h2>
          <p className="text-teal-200 text-xs mt-0.5">{doctor.specialization}</p>
        </div>
        <div className="p-5 grid grid-cols-2 gap-3 text-xs text-gray-600">
          <div><span className="text-gray-400">Qualification: </span>{doctor.qualification}</div>
          <div><span className="text-gray-400">Experience: </span>{doctor.experience_years} years</div>
          <div><span className="text-gray-400">Fee: </span>₹{Number(doctor.consultation_fee).toLocaleString()}</div>
          <div><span className="text-gray-400">License: </span>{doctor.license_number}</div>
          <div><span className="text-gray-400">Hospital: </span>{doctor.hospital_name || 'N/A'}</div>
          <div><span className="text-gray-400">Availability: </span>
            <DoctorStatusBadge status={doctor.availability_status} />
          </div>
          {doctor.bio && (
            <div className="col-span-2">
              <span className="text-gray-400">Bio: </span>{doctor.bio}
            </div>
          )}
        </div>
      </div>

      {/* Slots Management */}
      <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-5">
        <h3 className="text-sm font-semibold text-gray-900 mb-4">
          Manage Availability Slots
        </h3>

        {/* Add Slot */}
        <div className="flex flex-wrap gap-2 mb-4 p-3 bg-gray-50 rounded-lg">
          <select value={newSlot.day} onChange={e => setNewSlot(p => ({...p, day: e.target.value}))}
            className="px-2 py-1.5 text-xs border border-gray-300 rounded-md focus:outline-none focus:ring-1 focus:ring-teal-500">
            {DAYS.map(d => <option key={d} value={d}>{DAY_LABELS[d]}</option>)}
          </select>
          <input type="time" value={newSlot.start_time}
            onChange={e => setNewSlot(p => ({...p, start_time: e.target.value}))}
            className="px-2 py-1.5 text-xs border border-gray-300 rounded-md focus:outline-none focus:ring-1 focus:ring-teal-500"/>
          <span className="flex items-center text-xs text-gray-400">to</span>
          <input type="time" value={newSlot.end_time}
            onChange={e => setNewSlot(p => ({...p, end_time: e.target.value}))}
            className="px-2 py-1.5 text-xs border border-gray-300 rounded-md focus:outline-none focus:ring-1 focus:ring-teal-500"/>
          <button onClick={handleAddSlot} disabled={slotLoading}
            className="px-3 py-1.5 text-xs font-medium text-white bg-teal-600
                       rounded-md hover:bg-teal-700 disabled:opacity-50">
            {slotLoading ? '...' : '+ Add Slot'}
          </button>
        </div>

        {/* Slot List */}
        {slots.length === 0 ? (
          <p className="text-xs text-gray-400 text-center py-4">
            No slots added yet. Add your availability above.
          </p>
        ) : (
          <div className="space-y-2">
            {slots.map(slot => (
              <div key={slot.id}
                className="flex items-center justify-between bg-teal-50 border
                           border-teal-100 rounded-lg px-3 py-2">
                <div className="flex items-center gap-3">
                  <span className="text-xs font-medium text-teal-800 w-20">
                    {DAY_LABELS[slot.day]}
                  </span>
                  <span className="text-xs text-teal-600">
                    {slot.start_time} – {slot.end_time}
                  </span>
                </div>
                <button onClick={() => handleDeleteSlot(slot.id)}
                  className="text-xs text-red-500 hover:text-red-700 font-medium">
                  Remove
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default DoctorMyProfilePage;
